create table "SUS_ROLES" (  "ROLE_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "ROLE_NAME" varchar2(255) not null, constraint sus_roles_role_id_pk primary key ( "ROLE_ID" )  );
create table "SUS_SCHOOLS" (  "SCHOOL_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "SCHOOL_NAME" varchar2(255) not null, constraint sus_schools_school_id_pk primary key ( "SCHOOL_ID" )  );
create table "SUS_USERS" (  "USER_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "FULL_NAME" varchar2(255) null, "EMAIL" varchar2(255) not null, "ROLE_ID" number(19,0) not null, "SCHOOL_ID" number(19,0) null, "CREATED_AT" date not null, constraint sus_users_role_id_fk foreign key ( "ROLE_ID" ) references "SUS_ROLES" ( "ROLE_ID" ) on delete cascade, constraint sus_users_school_id_fk foreign key ( "SCHOOL_ID" ) references "SUS_SCHOOLS" ( "SCHOOL_ID" ) on delete set null, constraint sus_users_user_id_pk primary key ( "USER_ID" )  );
create table "SUS_EVENTS" (  "EVENT_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "SCHOOL_ID" number(19,0) not null, "ENTERED_BY" number(19,0) not null, "EVENT_MONTH" number(10,0) not null, "EVENT_YEAR" number(10,0) not null, "EVENT_NAME" varchar2(255) not null, "EVENT_TYPE" varchar2(255) not null, "EVENT_DATE" date not null, "DESCRIPTION" clob not null, "ATTACHMENT_PATH" varchar2(255) null, "CREATED_AT" date not null, constraint sus_events_school_id_fk foreign key ( "SCHOOL_ID" ) references "SUS_SCHOOLS" ( "SCHOOL_ID" ) on delete cascade, constraint sus_events_entered_by_fk foreign key ( "ENTERED_BY" ) references "SUS_USERS" ( "USER_ID" ) on delete cascade, constraint sus_events_event_id_pk primary key ( "EVENT_ID" )  );
create table "SUS_SUSTAINABILITY_PERIOD" (  "PERIOD_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "DATA_MONTH" number(10,0) not null, "DATA_YEAR" number(10,0) not null, "CREATED_BY" number(19,0) not null, "CREATED_AT" date not null, constraint su_sustainabil_per_crea_by_fk foreign key ( "CREATED_BY" ) references "SUS_USERS" ( "USER_ID" ) on delete cascade, constraint su_sustainabil_per_per_id_pk primary key ( "PERIOD_ID" )  );
create table "SUS_PAPER_CONSUMPTION" (  "PAPER_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "PERIOD_ID" number(19,0) not null, "PAPER_REAMS" number(10, 2) not null, "SHEETS_PER_REAM" number(10, 2) not null, constraint su_pape_consumptio_perio_id_fk foreign key ( "PERIOD_ID" ) references "SUS_SUSTAINABILITY_PERIOD" ( "PERIOD_ID" ) on delete cascade, constraint su_pape_consumptio_pape_id_pk primary key ( "PAPER_ID" )  );
create table "SUS_ELECTRICITY_CONSUMPTION" (  "ELECTRICITY_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "PERIOD_ID" number(19,0) not null, "UNITS_KWH" number(12, 2) not null, "TOTAL_COST" number(15, 2) not null, constraint su_electric_consumpt_per_id_fk foreign key ( "PERIOD_ID" ) references "SUS_SUSTAINABILITY_PERIOD" ( "PERIOD_ID" ) on delete cascade, constraint su_electr_consum_electr_id_pk primary key ( "ELECTRICITY_ID" )  );
create table "SUS_WASTE_GENERATION" (  "WASTE_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "PERIOD_ID" number(19,0) not null, "ORGANIC_KG" number(10, 2) not null, "RECYCLABLE_KG" number(10, 2) not null, "OTHER_KG" number(10, 2) not null, constraint su_wast_generatio_perio_id_fk foreign key ( "PERIOD_ID" ) references "SUS_SUSTAINABILITY_PERIOD" ( "PERIOD_ID" ) on delete cascade, constraint su_wast_generatio_wast_id_pk primary key ( "WASTE_ID" )  );
create table "SUS_GENERATOR_USAGE" (  "GENERATOR_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "PERIOD_ID" number(19,0) not null, "AVG_RUNNING_HOURS" number(10, 2) not null, "FUEL_LITRES" number(12, 2) not null, constraint su_generato_usag_perio_id_fk foreign key ( "PERIOD_ID" ) references "SUS_SUSTAINABILITY_PERIOD" ( "PERIOD_ID" ) on delete cascade, constraint su_generat_usa_generat_id_pk primary key ( "GENERATOR_ID" )  );
create table "SUS_BUSINESS_TRAVEL" (  "TRAVEL_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "PERIOD_ID" number(19,0) not null, "TRAVEL_KM" number(12, 2) not null, "FUEL_LITRES" number(12, 2) not null, constraint su_busines_trave_perio_id_fk foreign key ( "PERIOD_ID" ) references "SUS_SUSTAINABILITY_PERIOD" ( "PERIOD_ID" ) on delete cascade, constraint su_busines_trave_trave_id_pk primary key ( "TRAVEL_ID" )  );
create table "SUS_WATER_CONSUMPTION" (  "WATER_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "PERIOD_ID" number(19,0) not null, "UNITS" number(12, 2) not null, "PRICE_PER_UNIT" number(10, 2) not null, constraint su_wate_consumptio_perio_id_fk foreign key ( "PERIOD_ID" ) references "SUS_SUSTAINABILITY_PERIOD" ( "PERIOD_ID" ) on delete cascade, constraint su_wate_consumptio_wate_id_pk primary key ( "WATER_ID" )  );
create table "SUS_CARBON_METRICS" (  "CARBON_ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "PERIOD_ID" number(19,0) not null, "AQI_SCORE" number(10, 2) not null, "CARBON_FOOTPRINT" number(15, 2) not null, "ENTERED_BY" number(19,0) not null, "CREATED_AT" date not null, constraint su_carbo_metric_perio_id_fk foreign key ( "PERIOD_ID" ) references "SUS_SUSTAINABILITY_PERIOD" ( "PERIOD_ID" ) on delete cascade, constraint su_carbo_metric_entere_by_fk foreign key ( "ENTERED_BY" ) references "SUS_USERS" ( "USER_ID" ) on delete cascade, constraint su_carbo_metric_carbo_id_pk primary key ( "CARBON_ID" )  );
create table "SUS_PERSONAL_ACCESS_TOKENS" (  "ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "TOKENABLE_TYPE" varchar2(255) not null, "TOKENABLE_ID" number(19,0) not null, "NAME" clob not null, "TOKEN" varchar2(64) not null, "ABILITIES" clob null, "LAST_USED_AT" timestamp null, "EXPIRES_AT" timestamp null, "CREATED_AT" timestamp null, "UPDATED_AT" timestamp null, constraint su_persona_acces_token_id_pk primary key ( "ID" )  );
create table "SUS_ANNUAL_METRICS" (  "ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "YEAR" number(10,0) not null, "SOLAR_OFFSET_KWH" number(15, 2) null, "CREATED_AT" timestamp null, "UPDATED_AT" timestamp null, constraint sus_annual_metrics_id_pk primary key ( "ID" )  );
create table "SUS_SESSIONS" (  "ID" varchar2(255) not null, "USER_ID" number(19,0) null, "IP_ADDRESS" varchar2(45) null, "USER_AGENT" clob null, "PAYLOAD" clob not null, "LAST_ACTIVITY" number(10,0) not null, constraint sus_sessions_id_pk primary key ( "ID" )  );
create table "SUS_CACHE" (  "KEY" varchar2(255) not null, "VALUE" clob not null, "EXPIRATION" number(10,0) not null, constraint sus_cache_key_pk primary key ( "KEY" )  );
create table "SUS_CACHE_LOCKS" (  "KEY" varchar2(255) not null, "OWNER" varchar2(255) not null, "EXPIRATION" number(10,0) not null, constraint sus_cache_locks_key_pk primary key ( "KEY" )  );
create table "SUS_JOBS" (  "ID" number(19,0) GENERATED BY DEFAULT ON NULL AS IDENTITY not null, "QUEUE" varchar2(255) not null, "PAYLOAD" clob not null, "ATTEMPTS" number(3,0) not null, "RESERVED_AT" number(10,0) null, "AVAILABLE_AT" number(10,0) not null, "CREATED_AT" number(10,0) not null, constraint sus_jobs_id_pk primary key ( "ID" )  );
alter table "SUS_ROLES" add constraint sus_roles_role_name_uk unique ( "ROLE_NAME" );
alter table "SUS_USERS" add constraint sus_users_email_uk unique ( "EMAIL" );
alter table "SUS_SUSTAINABILITY_PERIOD" add constraint su_sustainab_pe_da_mo_da_ye_uk unique ( "DATA_MONTH", "DATA_YEAR" );
select column_name from all_tab_cols where upper(owner) = upper('BNUCMS') and upper(table_name) = upper('SUS_users') order by column_id;
alter table "SUS_USERS" add ( "PASSWORD" varchar2(255) not null );
