alter table "SUS_PERSONAL_ACCESS_TOKENS" add constraint su_persona_acces_token_toke_uk unique ( "TOKEN" );
create index su_perso_acc_tok_expi_at_in on "SUS_PERSONAL_ACCESS_TOKENS" ( "EXPIRES_AT" );
SELECT decode(nullable, 'Y', 1, 0) as nullable FROM all_tab_cols WHERE upper(owner) = upper('BNUCMS') AND upper(table_name) = upper('SUS_events') AND upper(column_name) = upper('school_id');
alter table "SUS_EVENTS" modify "SCHOOL_ID" number(19,0) null;
