alter table "SUS_ELECTRICITY_CONSUMPTION" add ( "KWH_SOLAR_OFFSET" number(10, 2) null );
alter table "SUS_WASTE_GENERATION" add ( "TOTAL_WASTE" number(10, 2) null );
alter table "SUS_WASTE_GENERATION" add ( "PER_CAPITA_WASTE" number(10, 4) null );
alter table "SUS_GENERATOR_USAGE" add ( "TOTAL_HOURS" number(10, 2) null );
alter table "SUS_GENERATOR_USAGE" add ( "DIESEL_LITRES" number(10, 2) null );
