SELECT cols.column_name FROM all_constraints cons, all_cons_columns cols WHERE upper(cols.table_name) = upper('SUS_BUSINESS_TRAVEL') AND upper(cons.owner) = upper('BNUCMS') AND cons.constraint_type = 'P' AND cons.constraint_name = cols.constraint_name AND cons.owner = cols.owner AND cols.position = 1 ORDER BY cols.table_name, cols.position;
